const input = $input.first().json;
const error = input.body || input;

// Extract error details
const errorData = {
  workflow_id: error.workflow?.id || error.workflowId || 'unknown',
  workflow_name: error.workflow?.name || error.workflowName || 'Unknown Workflow',
  execution_id: error.execution?.id || error.executionId || 'unknown',
  node_name: error.node?.name || error.nodeName || 'unknown',
  error_message: error.error?.message || error.message || JSON.stringify(error).substring(0, 500),
  error_type: error.error?.name || error.errorType || 'UnknownError',
  stack_trace: error.error?.stack || error.stack || null,
  timestamp: new Date().toISOString(),
  context: {
    input_data: error.inputData || null,
    node_type: error.node?.type || error.nodeType || null,
    retry_count: error.retryCount || 0
  }
};

// Generate error pattern for matching
const errorPattern = `${errorData.error_type}: ${errorData.error_message.substring(0, 100)}`;

return {
  json: {
    ...errorData,
    error_pattern: errorPattern,
    severity: determineSeverity(errorData),
    recoverable: isRecoverable(errorData)
  }
};

function determineSeverity(err) {
  const critical = ['ECONNREFUSED', 'ETIMEDOUT', 'Authentication', 'Permission', 'OutOfMemory', 'FATAL', 'CRASH'];
  const high = ['TypeError', 'ReferenceError', 'SyntaxError', 'ValidationError'];
  const medium = ['NetworkError', 'TimeoutError', 'RateLimitError'];

  for (const c of critical) {
    if (err.error_message.includes(c) || err.error_type.includes(c)) return 'critical';
  }
  for (const h of high) {
    if (err.error_message.includes(h) || err.error_type.includes(h)) return 'high';
  }
  for (const m of medium) {
    if (err.error_message.includes(m) || err.error_type.includes(m)) return 'medium';
  }
  return 'low';
}

function isRecoverable(err) {
  const recoverable = ['timeout', 'rate limit', 'temporary', 'retry', 'network', 'connection', 'ECONNRESET', 'ETIMEDOUT'];
  const msg = err.error_message.toLowerCase();
  return recoverable.some(r => msg.includes(r));
}

const solution = $input.first().json;
const errorData = $('Parse Error').first().json;

// Attempt auto-recovery if solution suggests it
const response = {
  status: 'solution_applied',
  error_pattern: errorData.error_pattern,
  solution: solution.solution,
  workflow_id: errorData.workflow_id,
  workflow_name: errorData.workflow_name,
  timestamp: new Date().toISOString(),
  message: `Found solution for error: ${solution.solution.substring(0, 200)}`,
  auto_recovery: solution.auto_recovery || false,
  recovery_action: solution.recovery_action || null,
  should_retry: solution.should_retry || false
};

return { json: response };

