const errorData = $('Parse Error').first().json;

// Format critical alert with recovery info
const alert = {
  status: 'critical_error',
  priority: 'URGENT',
  error: errorData,
  message: `CRITICAL ERROR in ${errorData.workflow_name}\n\nNode: ${errorData.node_name}\nError: ${errorData.error_message}\nTime: ${errorData.timestamp}`,
  requires_immediate_attention: true,
  notification_channels: ['sms', 'email', 'slack'],
  timestamp: new Date().toISOString(),
  recoverable: errorData.recoverable,
  auto_retry_suggested: errorData.recoverable && errorData.context.retry_count < 3
};

return { json: alert };

const errorData = $('Parse Error').first().json;

const alert = {
  status: 'high_priority_error',
  priority: 'HIGH',
  error: errorData,
  message: `HIGH PRIORITY ERROR in ${errorData.workflow_name}\n\nNode: ${errorData.node_name}\nError: ${errorData.error_message}`,
  notification_channels: ['email', 'slack'],
  timestamp: new Date().toISOString()
};

return { json: alert };

const errorData = $('Parse Error').first().json;

const logEntry = {
  status: 'error_logged',
  priority: errorData.severity,
  error: errorData,
  message: `Error logged for ${errorData.workflow_name}: ${errorData.error_message.substring(0, 100)}`,
  notification_channels: [],
  timestamp: new Date().toISOString()
};

return { json: logEntry };

const errorData = $('Parse Error').first().json;
let solutionFound = false;
let alertData = { status: 'processed' };
let autoFixResult = null;
let smsResult = null;

try {
  const solutionCheck = $('Solution Found?').first().json;
  solutionFound = solutionCheck?.found || false;
} catch(e) {}

try {
  if ($('Critical Alert').first()) alertData = $('Critical Alert').first().json;
  else if ($('High Priority Alert').first()) alertData = $('High Priority Alert').first().json;
  else if ($('Log Only').first()) alertData = $('Log Only').first().json;
  else if ($('Apply Solution').first()) alertData = $('Apply Solution').first().json;
} catch(e) {}

try {
  autoFixResult = $('Auto Retry Check').first().json;
} catch(e) {}

try {
  smsResult = $('SMS Critical Alert').first().json;
} catch(e) {}

const suggestions = $input.first().json;

return {
  json: {
    success: true,
    error_handled: true,
    original_error: {
      workflow: errorData.workflow_name,
      node: errorData.node_name,
      message: errorData.error_message,
      severity: errorData.severity,
      recoverable: errorData.recoverable
    },
    solution_found: solutionFound,
    action_taken: alertData?.status || 'logged',
    auto_fix: autoFixResult?.auto_fix_attempted || false,
    sms_sent: smsResult?.success || false,
    suggestions: suggestions?.suggestions || [],
    self_annealing: {
      error_logged: true,
      pattern_recorded: errorData.error_pattern,
      introspection_triggered: true
    },
    timestamp: new Date().toISOString()
  }
};

// Advanced error pattern matching with solutions
const errorData = $input.first().json;
const errorMsg = errorData.error_message.toLowerCase();
const errorType = errorData.error_type;

// Known error patterns with solutions and auto-fix actions
const patterns = [
  {
    pattern: /econnrefused/i,
    category: 'connection',
    solution: 'Service is not running. Restart the service.',
    auto_fix: 'restart_service',
    priority: 'critical'
  },
  {
    pattern: /etimedout|timeout/i,
    category: 'timeout',
    solution: 'Request timed out. Retry with longer timeout or check network.',
    auto_fix: 'retry_with_backoff',
    priority: 'high'
  },
  {
    pattern: /rate.?limit|too.?many.?requests|429/i,
    category: 'rate_limit',
    solution: 'Rate limited. Wait and retry with exponential backoff.',
    auto_fix: 'exponential_backoff',
    priority: 'medium'
  },
  {
    pattern: /auth|unauthorized|401|403|forbidden/i,
    category: 'auth',
    solution: 'Authentication failed. Check credentials and tokens.',
    auto_fix: 'refresh_credentials',
    priority: 'high'
  },
  {
    pattern: /not.?found|404/i,
    category: 'not_found',
    solution: 'Resource not found. Verify the path or ID.',
    auto_fix: null,
    priority: 'medium'
  },
  {
    pattern: /permission|access.?denied/i,
    category: 'permission',
    solution: 'Permission denied. Check file/resource permissions.',
    auto_fix: null,
    priority: 'high'
  },
  {
    pattern: /memory|heap|oom/i,
    category: 'memory',
    solution: 'Out of memory. Reduce data size or increase memory allocation.',
    auto_fix: 'restart_service',
    priority: 'critical'
  },
  {
    pattern: /syntax|parse|json/i,
    category: 'syntax',
    solution: 'Syntax error. Check input format and data structure.',
    auto_fix: null,
    priority: 'medium'
  }
];

// Find matching pattern
let matchedPattern = null;
for (const p of patterns) {
  if (p.pattern.test(errorMsg) || p.pattern.test(errorType)) {
    matchedPattern = p;
    break;
  }
}

return {
  json: {
    ...errorData,
    pattern_match: matchedPattern ? {
      category: matchedPattern.category,
      solution: matchedPattern.solution,
      auto_fix: matchedPattern.auto_fix,
      priority: matchedPattern.priority,
      matched: true
    } : {
      category: 'unknown',
      solution: 'Unknown error. Manual investigation required.',
      auto_fix: null,
      priority: 'medium',
      matched: false
    }
  }
};

