const slackMessage = {
  channel: '#alerts',
  username: 'n8n Error Bot',
  icon_emoji: ':warning:',
  attachments: [{
    color: alert.priority === 'URGENT' ? 'danger' : 'warning',
    title: `${alert.priority} Alert: ${alert.error?.workflow_name || 'Unknown Workflow'}`,
    text: alert.message,
