      { title: 'Node', value: alert.error?.node_name || 'Unknown', short: true },
      { title: 'Severity', value: alert.error?.severity || 'Unknown', short: true }
    ],
    ts: Date.now() / 1000
  }]
};

// Log what would be sent to Slack
console.log('SLACK_ALERT:', JSON.stringify(slackMessage));

return {
  json: {
    ...alert,
    slack_notification: {
      would_send: slackMessage,
      status: 'stub_logged'
    }
  }
};

